function Scene(){
  const { useFrame, ScreenOverlay, InfoPoint, Html } = helpers;
  const palette = { primaryClassA:'#2563eb', primaryClassB:'#dc2626', boundary:'#111827', margin:'#10b981', supportHighlight:'#f59e0b', bg:'#f9fafb', grid:'#e5e7eb', axis:'#6b7280' };
  let datasetMode=0; // 0 Separable,1 Overlap,2 XOR
  let cPenalty=1.0; // min 0.1 max 100
  let classWeightPos=1.0; // min 0.2 max 5
  let kernelMode=0; // 0 Linear,1 Poly,2 RBF
  let rbfGamma=0.7; // min 0.05 max 10
  let selectedAddClass=+1;
  let supportVectorCount=0;
  let trainingStatus='Converged';
  let trainingProgress=1.0;
  let iterationCount=0;

  function preset(mode){
    if(mode===2) return [{id:1,x:-2,y:-2,label:1},{id:2,x:2,y:2,label:1},{id:3,x:-2,y:2,label:-1},{id:4,x:2,y:-2,label:-1}].map(p=>Object.assign(p,{isSupport:false,isMisclassified:false}));
    if(mode===1) return [{id:1,x:-2.6,y:1.5,label:1},{id:2,x:-1.2,y:0.2,label:1},{id:3,x:0.2,y:1.2,label:1},{id:4,x:1.8,y:0.7,label:1},{id:5,x:-0.5,y:-0.8,label:-1},{id:6,x:1.1,y:-0.3,label:-1},{id:7,x:2.2,y:-1.2,label:-1},{id:8,x:-1.8,y:-1.4,label:-1}].map(p=>Object.assign(p,{isSupport:false,isMisclassified:false}));
    return [{id:1,x:-3,y1:2,y:2,label:1},{id:2,x:-2.2,y:0.8,label:1},{id:3,x:-1.3,y:2.7,label:1},{id:4,x:1.4,y:-1.8,label:-1},{id:5,x:2.6,y:-0.8,label:-1},{id:6,x:3.1,y:-2.3,label:-1}].map(p=>{delete p.y1; return Object.assign(p,{isSupport:false,isMisclassified:false});});
  }

  const [params,setParams]=React.useState({datasetMode,cPenalty,classWeightPos,kernelMode,rbfGamma,selectedAddClass,stepIndex:0});
  const [points,setPoints]=React.useState(preset(0));
  const [model,setModel]=React.useState({a:0.6,b:1,c:0,margin:1.2,prevA:0.6,prevB:1,prevC:0,prevM:1.2,t:1,supportAnim:{}});
  const [status,setStatus]=React.useState({trainingStatus:'Converged',trainingProgress:1,iterationCount:0,supportVectorCount:0});
  const [dragId,setDragId]=React.useState(null);

  function decisionAt(x,y,m){
    if(params.kernelMode===0) return m.a*x + m.b*y + m.c;
    if(params.kernelMode===1) return 0.2*(x*x - y*y) + 0.6*x + 0.4*y + m.c;
    var g=params.rbfGamma; return Math.sin(x*g*0.8)+Math.cos(y*g*0.7)+0.3*x-0.2*y+m.c;
  }

  React.useEffect(function(){
    setPoints(preset(params.datasetMode));
  },[params.datasetMode]);

  React.useEffect(function(){
    setStatus(s=>({trainingStatus:'Training…',trainingProgress:0,iterationCount:s.iterationCount+1,supportVectorCount:s.supportVectorCount}));
    var bias=(params.classWeightPos-1)*0.4 - Math.log10(params.cPenalty)*0.35;
    var a=0.6, b=1;
    if(params.kernelMode===1){a=0.35;b=1;} if(params.kernelMode===2){a=0.15;b=1;}
    var margin=Math.max(0.35,1.8/(Math.log10(params.cPenalty+1)+1));
    setModel(m=>({a,b,c:bias,margin,prevA:m.a,prevB:m.b,prevC:m.c,prevM:m.margin,t:0,supportAnim:m.supportAnim}));
  },[params.cPenalty,params.classWeightPos,params.kernelMode,params.rbfGamma,points.length]);

  useFrame((st,dt)=>{
    setModel(m=>{ if(m.t>=1) return m; var t=Math.min(1,m.t+dt*2); return Object.assign({},m,{t:t});});
    setStatus(s=>{
      if(s.trainingProgress>=1 && s.trainingStatus==='Converged') return s;
      var p=Math.min(1,s.trainingProgress+dt*2); return {trainingStatus:p<1?'Training…':'Converged',trainingProgress:p,iterationCount:s.iterationCount,supportVectorCount:s.supportVectorCount};
    });
  });

  return React.createElement(React.Fragment,null,
    React.createElement('color',{attach:'background',args:[palette.bg]}),
    React.createElement('ambientLight',{args:[0xffffff,0.8]}),
    React.createElement('directionalLight',{args:[0xffffff,0.4],position:[5,8,10]}),
    React.createElement(helpers.InfoPoint,{label:'MAXIMUM MARGIN',explanation:'The SVM chooses the boundary that makes the gap between classes as wide as possible, improving generalization.',position:[-3.2,3.8,0.2],color:'#10b981'}),
    React.createElement(helpers.InfoPoint,{label:'SUPPORT VECTORS',explanation:'These are the critical points that touch or violate the margin; they alone determine the boundary’s final position.',position:[-8.8,-3.8,0.2],color:'#f59e0b'}),
    React.createElement(helpers.InfoPoint,{label:'SOFT MARGIN (C)',explanation:'C controls how much the model penalizes margin violations; high C fits training data more, low C prefers a wider margin.',position:[-1.8,4.6,0.2],color:'#111827'}),
    React.createElement(helpers.InfoPoint,{label:'KERNEL TRICK',explanation:'Kernels let the SVM act like it’s drawing a straight line in a higher-dimensional feature space, producing a curved boundary here.',position:[3.4,5.3,0.2],color:'#111827'}),
    React.createElement(helpers.InfoPoint,{label:'GAMMA (RBF)',explanation:'Gamma controls how local each point’s influence is; higher gamma makes tighter, more complex boundaries.',position:[4.2,3.9,0.2],color:'#111827'}),
    React.createElement(helpers.InfoPoint,{label:'CLASS WEIGHTS',explanation:'Heavier weighting makes the SVM treat errors on that class as more costly, shifting the boundary to reduce those errors.',position:[-10.4,5.0,0.2],color:'#2563eb'}),
    React.createElement(ScreenOverlay,null,
      React.createElement('div',{style:{position:'absolute',top:'16px',left:'16px',width:'320px',background:'#ffffff',border:'1px solid #e5e7eb',borderRadius:'12px',padding:'16px',pointerEvents:'auto'}},'Controls'),
      React.createElement('div',{style:{position:'absolute',top:'16px',right:'16px',width:'344px',background:'rgba(250,245,235,0.92)',border:'1px solid rgba(0,0,0,0.1)',borderRadius:'12px',padding:'16px',pointerEvents:'auto'}},'SCAFFOLDED STEPS')
    )
  );
}
return Scene;
